    private const string PathHandlerClass = """
                                            // <auto-generated/>
                                            using System;
                                            using System.Collections;
                                            using System.Collections.Generic;
                                            using System.IO;
                                            using System.Linq;
                                            using System.Text;
                                            using System.Threading.Tasks;

                                            using Avalonia.DBus.Wire;

                                            #pragma warning disable
                                            #nullable enable
                                            namespace Avalonia.DBus.SourceGen
                                            {
                                                internal sealed class PathHandler : ICollection<IDBusInterfaceHandler>
                                                {
                                                    private const string ErrorUnknownInterface = "org.freedesktop.DBus.Error.UnknownInterface";
                                                    private const string ErrorUnknownMethod = "org.freedesktop.DBus.Error.UnknownMethod";
                                                    private const string ErrorUnknownProperty = "org.freedesktop.DBus.Error.UnknownProperty";
                                                    private const string PropertiesIntrospectXml = "<interface name=\"org.freedesktop.DBus.Properties\">\n  <method name=\"Get\">\n    <arg name=\"interface\" type=\"s\" direction=\"in\"/>\n    <arg name=\"property\" type=\"s\" direction=\"in\"/>\n    <arg name=\"value\" type=\"v\" direction=\"out\"/>\n  </method>\n  <method name=\"Set\">\n    <arg name=\"interface\" type=\"s\" direction=\"in\"/>\n    <arg name=\"property\" type=\"s\" direction=\"in\"/>\n    <arg name=\"value\" type=\"v\" direction=\"in\"/>\n  </method>\n  <method name=\"GetAll\">\n    <arg name=\"interface\" type=\"s\" direction=\"in\"/>\n    <arg name=\"properties\" type=\"a{sv}\" direction=\"out\"/>\n  </method>\n  <signal name=\"PropertiesChanged\">\n    <arg name=\"interface\" type=\"s\"/>\n    <arg name=\"changed_properties\" type=\"a{sv}\"/>\n    <arg name=\"invalidated_properties\" type=\"as\"/>\n  </signal>\n</interface>\n";
                                                    private static readonly string s_machineId = ResolveMachineId();
                                                    private readonly List<IDBusInterfaceHandler> _dbusInterfaces = new();
                                                    private string[] _childNodes = Array.Empty<string>();

                                                    public PathHandler(string path)
                                                    {
                                                        Path = new DBusObjectPath(path);
                                                    }

                                                    public DBusObjectPath Path { get; }

                                                    public Task<DBusMessage> HandleMethodAsync(DBusMessage request)
                                                    {
                                                        string? iface = request.Interface;
                                                        if (string.IsNullOrEmpty(iface))
                                                        {
                                                            return Task.FromResult(request.CreateError(ErrorUnknownInterface, "Unknown interface"));
                                                        }

                                                        switch (iface)
                                                        {
                                                            case "org.freedesktop.DBus.Properties":
                                                                return Task.FromResult(HandleProperties(request));
                                                            case "org.freedesktop.DBus.Introspectable":
                                                                return Task.FromResult(HandleIntrospect(request));
                                                            case "org.freedesktop.DBus.Peer":
                                                                return Task.FromResult(HandlePeer(request));
                                                            default:
                                                                IDBusInterfaceHandler? handler = _dbusInterfaces.FirstOrDefault(x => x.InterfaceName == iface);
                                                                if (handler is null)
                                                                {
                                                                    return Task.FromResult(request.CreateError(ErrorUnknownInterface, "Unknown interface"));
                                                                }

                                                                return handler.HandleMethodAsync(request);
                                                        }
                                                    }

                                                    public IDisposable Register(DBusConnection connection)
                                                    {
                                                        var registrations = new List<IDisposable>();
                                                        foreach (var handler in _dbusInterfaces)
                                                        {
                                                            registrations.Add(connection.RegisterObject(Path, handler.InterfaceName, HandleMethodAsync));
                                                        }

                                                        registrations.Add(connection.RegisterObject(Path, "org.freedesktop.DBus.Properties", HandleMethodAsync));
                                                        registrations.Add(connection.RegisterObject(Path, "org.freedesktop.DBus.Introspectable", HandleMethodAsync));
                                                        registrations.Add(connection.RegisterObject(Path, "org.freedesktop.DBus.Peer", HandleMethodAsync));
                                                        return new CompositeDisposable(registrations);
                                                    }

                                                    public void Add(IDBusInterfaceHandler item)
                                                    {
                                                        item.PathHandler = this;
                                                        _dbusInterfaces.Add(item);
                                                    }

                                                    public bool Contains(IDBusInterfaceHandler item) => _dbusInterfaces.Contains(item);

                                                    public bool Remove(IDBusInterfaceHandler item)
                                                    {
                                                        item.PathHandler = null;
                                                        return _dbusInterfaces.Remove(item);
                                                    }

                                                    public void Clear()
                                                    {
                                                        foreach (var item in _dbusInterfaces)
                                                        {
                                                            item.PathHandler = null;
                                                        }
                                                        _dbusInterfaces.Clear();
                                                    }

                                                    public int Count => _dbusInterfaces.Count;

                                                    public bool IsReadOnly => false;

                                                    public void CopyTo(IDBusInterfaceHandler[] array, int arrayIndex) => _dbusInterfaces.CopyTo(array, arrayIndex);

                                                    public IEnumerator<IDBusInterfaceHandler> GetEnumerator() => _dbusInterfaces.GetEnumerator();

                                                    IEnumerator IEnumerable.GetEnumerator() => _dbusInterfaces.GetEnumerator();

                                                    internal void SetChildNodes(string[] childNodes)
                                                    {
                                                        _childNodes = childNodes ?? Array.Empty<string>();
                                                    }

                                                    private DBusMessage HandleProperties(DBusMessage request)
                                                    {
                                                        switch (request.Member)
                                                        {
                                                            case "Get":
                                                            {
                                                                if (request.Body.Count < 2)
                                                                {
                                                                    return request.CreateError(ErrorUnknownMethod, "Invalid Get arguments.");
                                                                }

                                                                string iface = (string)request.Body[0];
                                                                string name = (string)request.Body[1];
                                                                IDBusInterfaceHandler? handler = _dbusInterfaces.FirstOrDefault(x => x.InterfaceName == iface);
                                                                if (handler is null)
                                                                {
                                                                    return request.CreateError(ErrorUnknownInterface, "Unknown interface");
                                                                }

                                                                if (!handler.TryGetProperty(name, out DBusVariant value))
                                                                {
                                                                    return request.CreateError(ErrorUnknownProperty, "Unknown property");
                                                                }

                                                                return request.CreateReply(value);
                                                            }
                                                            case "GetAll":
                                                            {
                                                                if (request.Body.Count < 1)
                                                                {
                                                                    return request.CreateError(ErrorUnknownMethod, "Invalid GetAll arguments.");
                                                                }

                                                                string iface = (string)request.Body[0];
                                                                IDBusInterfaceHandler? handler = _dbusInterfaces.FirstOrDefault(x => x.InterfaceName == iface);
                                                                if (handler is null)
                                                                {
                                                                    return request.CreateError(ErrorUnknownInterface, "Unknown interface");
                                                                }

                                                                DBusDict<string, DBusVariant> props = handler.GetAllProperties();
                                                                return request.CreateReply(props);
                                                            }
                                                            case "Set":
                                                            {
                                                                if (request.Body.Count < 3)
                                                                {
                                                                    return request.CreateError(ErrorUnknownMethod, "Invalid Set arguments.");
                                                                }

                                                                string iface = (string)request.Body[0];
                                                                string name = (string)request.Body[1];
                                                                DBusVariant value = (DBusVariant)request.Body[2];
                                                                IDBusInterfaceHandler? handler = _dbusInterfaces.FirstOrDefault(x => x.InterfaceName == iface);
                                                                if (handler is null)
                                                                {
                                                                    return request.CreateError(ErrorUnknownInterface, "Unknown interface");
                                                                }

                                                                if (!handler.TrySetProperty(name, value))
                                                                {
                                                                    return request.CreateError(ErrorUnknownProperty, "Unknown property");
                                                                }

                                                                return request.CreateReply();
                                                            }
                                                            default:
                                                                return request.CreateError(ErrorUnknownMethod, "Unknown method");
                                                        }
                                                    }

                                                    private DBusMessage HandleIntrospect(DBusMessage request)
                                                    {
                                                        string xml = BuildIntrospectionXml();
                                                        return request.CreateReply(xml);
                                                    }

                                                    private DBusMessage HandlePeer(DBusMessage request)
                                                    {
                                                        switch (request.Member)
                                                        {
                                                            case "Ping":
                                                                return request.CreateReply();
                                                            case "GetMachineId":
                                                                return request.CreateReply(s_machineId);
                                                            default:
                                                                return request.CreateError(ErrorUnknownMethod, "Unknown method");
                                                        }
                                                    }

                                                    private string BuildIntrospectionXml()
                                                    {
                                                        var sb = new StringBuilder();
                                                        sb.Append("<node>");
                                                        foreach (var handler in _dbusInterfaces)
                                                        {
                                                            sb.Append(handler.IntrospectXml);
                                                        }

                                                        if (_dbusInterfaces.Count > 0)
                                                        {
                                                            sb.Append(PropertiesIntrospectXml);
                                                        }

                                                        foreach (var child in _childNodes)
                                                        {
                                                            sb.Append("<node name='");
                                                            sb.Append(child);
                                                            sb.Append("'/>");
                                                        }

                                                        sb.Append("</node>");
                                                        return sb.ToString();
                                                    }

                                                    private static string ResolveMachineId()
                                                    {
                                                        string[] paths = { "/etc/machine-id", "/var/lib/dbus/machine-id" };
                                                        foreach (string path in paths)
                                                        {
                                                            try
                                                            {
                                                                if (File.Exists(path))
                                                                {
                                                                    string text = File.ReadAllText(path).Trim();
                                                                    if (!string.IsNullOrEmpty(text))
                                                                    {
                                                                        return text;
                                                                    }
                                                                }
                                                            }
                                                            catch
                                                            {
                                                            }
                                                        }

                                                        return "unknown";
                                                    }
                                                }

                                                internal sealed class PathTree
                                                {
                                                    private readonly object _gate = new();
                                                    private readonly Dictionary<string, PathHandler> _handlers = new(StringComparer.Ordinal);
                                                    private readonly HashSet<string> _activePaths = new(StringComparer.Ordinal);
                                                    private readonly Dictionary<string, PathHandler> _activeHandlers = new(StringComparer.Ordinal);
                                                    private readonly string _rootPath;
                                                    private readonly string[] _rootSegments;

                                                    public PathTree(string rootPath)
                                                    {
                                                        _rootPath = NormalizePath(rootPath);
                                                        _rootSegments = SplitPath(_rootPath);
                                                        Path = _rootPath;
                                                        _handlers[_rootPath] = new PathHandler(_rootPath);
                                                    }

                                                    public string Path { get; }

                                                    public PathHandler AddPath(string path)
                                                    {
                                                        path = NormalizePath(path);
                                                        EnsureUnderRoot(path);
                                                        lock (_gate)
                                                        {
                                                            PathHandler handler = EnsureHandler(path);
                                                            if (_activePaths.Add(path))
                                                            {
                                                                RebuildActiveTree();
                                                            }

                                                            return handler;
                                                        }
                                                    }

                                                    public bool RemovePath(string path)
                                                    {
                                                        path = NormalizePath(path);
                                                        EnsureUnderRoot(path);
                                                        lock (_gate)
                                                        {
                                                            if (!_activePaths.Remove(path))
                                                            {
                                                                return false;
                                                            }

                                                            RebuildActiveTree();
                                                            return true;
                                                        }
                                                    }

                                                    public IDisposable Register(DBusConnection connection)
                                                    {
                                                        var registrations = new List<IDisposable>();
                                                        lock (_gate)
                                                        {
                                                            foreach (var handler in _activeHandlers.Values)
                                                            {
                                                                registrations.Add(handler.Register(connection));
                                                            }
                                                        }

                                                        return new CompositeDisposable(registrations);
                                                    }

                                                    private PathHandler EnsureHandler(string path)
                                                    {
                                                        if (!_handlers.TryGetValue(path, out PathHandler? handler))
                                                        {
                                                            handler = new PathHandler(path);
                                                            _handlers[path] = handler;
                                                        }

                                                        return handler;
                                                    }

                                                    private void RebuildActiveTree()
                                                    {
                                                        _activeHandlers.Clear();

                                                        var activeNodes = new HashSet<string>(StringComparer.Ordinal);
                                                        var children = new Dictionary<string, HashSet<string>>(StringComparer.Ordinal);

                                                        foreach (string path in _activePaths)
                                                        {
                                                            AddActivePath(path, activeNodes, children);
                                                        }

                                                        foreach (var pair in _handlers)
                                                        {
                                                            if (children.TryGetValue(pair.Key, out HashSet<string>? childNames))
                                                            {
                                                                string[] sortedChildren = childNames.OrderBy(static x => x, StringComparer.Ordinal).ToArray();
                                                                pair.Value.SetChildNodes(sortedChildren);
                                                            }
                                                            else
                                                            {
                                                                pair.Value.SetChildNodes(Array.Empty<string>());
                                                            }
                                                        }

                                                        foreach (string path in activeNodes)
                                                        {
                                                            if (_handlers.TryGetValue(path, out PathHandler? handler))
                                                            {
                                                                _activeHandlers[path] = handler;
                                                            }
                                                        }
                                                    }

                                                    private void AddActivePath(string path, HashSet<string> activeNodes, Dictionary<string, HashSet<string>> children)
                                                    {
                                                        EnsureHandler(path);

                                                        string[] segments = SplitPath(path);
                                                        string current = _rootPath;
                                                        activeNodes.Add(current);

                                                        for (int i = _rootSegments.Length; i < segments.Length; i++)
                                                        {
                                                            string child = segments[i];
                                                            string next = current == "/" ? "/" + child : current + "/" + child;
                                                            EnsureHandler(next);
                                                            activeNodes.Add(next);

                                                            if (!children.TryGetValue(current, out HashSet<string>? childSet))
                                                            {
                                                                childSet = new HashSet<string>(StringComparer.Ordinal);
                                                                children[current] = childSet;
                                                            }
                                                            childSet.Add(child);

                                                            current = next;
                                                        }
                                                    }

                                                    private static string NormalizePath(string path)
                                                    {
                                                        if (string.IsNullOrWhiteSpace(path))
                                                        {
                                                            throw new ArgumentException("Path must be provided.", nameof(path));
                                                        }

                                                        if (!path.StartsWith("/", StringComparison.Ordinal))
                                                        {
                                                            throw new ArgumentException("Path must start with '/'.", nameof(path));
                                                        }

                                                        if (path.Length > 1 && path.EndsWith("/", StringComparison.Ordinal))
                                                        {
                                                            path = path.TrimEnd('/');
                                                        }

                                                        return path;
                                                    }

                                                    private static string[] SplitPath(string path)
                                                    {
                                                        if (path == "/")
                                                        {
                                                            return Array.Empty<string>();
                                                        }

                                                        return path.Split(new[] { '/' }, StringSplitOptions.RemoveEmptyEntries);
                                                    }

                                                    private void EnsureUnderRoot(string path)
                                                    {
                                                        if (_rootPath == "/")
                                                        {
                                                            return;
                                                        }

                                                        if (string.Equals(path, _rootPath, StringComparison.Ordinal))
                                                        {
                                                            return;
                                                        }

                                                        if (!path.StartsWith(_rootPath, StringComparison.Ordinal) || path.Length <= _rootPath.Length || path[_rootPath.Length] != '/')
                                                        {
                                                            throw new ArgumentException("Path must be under the root path.", nameof(path));
                                                        }
                                                    }
                                                }

                                                internal sealed class CompositeDisposable : IDisposable
                                                {
                                                    private readonly IReadOnlyList<IDisposable> _items;

                                                    public CompositeDisposable(IReadOnlyList<IDisposable> items)
                                                    {
                                                        _items = items;
                                                    }

                                                    public void Dispose()
                                                    {
                                                        foreach (var item in _items)
                                                        {
                                                            item.Dispose();
                                                        }
                                                    }
                                                }
                                            }
                                            """;
}
